// ====================================================
// CONFIGURACIÓN RANGO DE FECHAS ====================================================

// Ajuste Chile UTC-3
const hoy = new Date();
hoy.setMinutes(hoy.getMinutes() + hoy.getTimezoneOffset() + 180);

// ===============================
// FECHA FIN → Último día hábil
// ===============================
const fechaFin = new Date(hoy);
fechaFin.setDate(fechaFin.getDate() - 1);

while (fechaFin.getDay() === 0 || fechaFin.getDay() === 6) {
  fechaFin.setDate(fechaFin.getDate() - 1);
}

// ===============================
// FECHA INICIO → Último viernes mes anterior
// ===============================
const fechaInicio = new Date(
  fechaFin.getFullYear(),
  fechaFin.getMonth(),
  0
);

while (fechaInicio.getDay() !== 5) {
  fechaInicio.setDate(fechaInicio.getDate() - 1);
}

// ===============================
// TEXTO PERIODO
// ===============================
const MESES = [
'enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'
];

const inicioTexto =
  String(fechaInicio.getDate()).padStart(2,'0') +
  ' de ' + MESES[fechaInicio.getMonth()];

const finTexto =
  String(fechaFin.getDate()).padStart(2,'0') +
  ' de ' + MESES[fechaFin.getMonth()];

const periodoTexto = `${inicioTexto} – ${finTexto}`;
const mesCurso = MESES[fechaFin.getMonth()].toUpperCase().slice(0,3);

// ===============================
// LISTA DE EXCEPCIONES
// ===============================
const excepciones = [
  "Andres Acevedo",
  "Camila Chavez",
  "DL Developer",
  "Henry Rivas",
  "Proyectos Digital Learning S.A.",
  "Sebastian Vidal",
  "Yara Martínez"
];

// ===============================
// OUTPUT
// ===============================
return {
  fechaInicio: fechaInicio.toISOString().slice(0,10),
  fechaFin: fechaFin.toISOString().slice(0,10),
  periodoTexto,
  mesCurso,
  excepciones
};

// =====================================================
// CÁLCULO DE DÍAS LABORABLES Y HORAS ESPERADAS
// =====================================================

const repo = $input.first().json;
const inicio = new Date(repo.fechaInicio);
const fin = new Date(repo.fechaFin);

let diasLaborables = 0;
let horasTotales = 0;

for (let d = new Date(inicio); d <= fin; d.setDate(d.getDate() + 1)) {

  const dia = d.getDay();

  if (dia >= 1 && dia <= 4) {
    diasLaborables++;
    horasTotales += 8;
  } else if (dia === 5) {
    diasLaborables++;
    horasTotales += 6.5;
  }
}

return {
  json: {
    diasLaborables,
    horasTotales: +horasTotales.toFixed(1),
    mesCurso: repo.mesCurso
  }
};

// ===============================
// PERSONAS FILTRADAS
// ===============================
const personasArray = $('Filtrar personas').all().map(p => p.json);

// Mapa por personId
const personas = Object.fromEntries(
  personasArray.map(p => [p.personId, p])
);

// Días laborales
const diasLaborables = $('Calculo de horas').first().json.diasLaborables;
const horasEsperadasPeriodo = $('Calculo de horas').first().json.horasTotales;

const resultados = [];
const horasPorPersona = {};

// ===============================
// CONSOLIDAR RESPUESTA TIME
// ===============================
for (const item of $input.all()) {

  const registros = item.json.time || [];

  if (!registros.length) continue;

  const personId = Number(registros[0].personid);

  const totalHoras = registros.reduce(
    (acc, r) => acc + Number(r.time || 0),
    0
  );

  horasPorPersona[personId] =
    (horasPorPersona[personId] || 0) + totalHoras;
}

// ===============================
// GENERAR RESULTADOS
// ===============================
for (const persona of personasArray) {

  const horasIngresadas =
    +(horasPorPersona[persona.personId] || 0).toFixed(1);

  const diferencia =
    +(horasEsperadasPeriodo - horasIngresadas).toFixed(1);

  const porcentaje = horasEsperadasPeriodo > 0
    ? Math.round((horasIngresadas / horasEsperadasPeriodo) * 100)
    : 0;

let estado =
  porcentaje >= 100 ? '✅ Al día' :
  porcentaje >= 80 ? '⚠️ Pendiente' :
  '❌ Atrasado';

  resultados.push({
    Area: "N/A",
    Nombre: persona.nombre,
    horasEsperadas: horasEsperadasPeriodo,
    horasIngresadas,
    diferencia,
    semanasPendientes:
      diferencia > 0 ? +((diferencia / 40).toFixed(1)) : 0,
    porcentaje,
    estado,
    diasLaborables
  });
}

return resultados.sort((a,b) => a.diferencia - b.diferencia);

// ===============================
// FUENTES DE DATOS
// ===============================
const datos = $input.all();
const repo = $('Repositorio').first().json;


// ===============================
// METADATA DEL REPORTE
// ===============================
const periodoInicio = repo.fechaInicio;
const periodoFin = repo.fechaFin;

// Valores globales (se repiten en todos los registros)
const diasLaborables =
  datos.length ? datos[0].json.diasLaborables : 0;

const horasEsperadasPeriodo =
  datos.length && !isNaN(datos[0].json.horasEsperadas)
    ? datos[0].json.horasEsperadas
    : 0;

const totalColaboradores = datos.length;


// ===============================
// RESUMEN ESTADÍSTICO
// ===============================
const alDia = datos.filter(i =>
  i.json.estado === '✅ Al día'
).length;

const pendientes = datos.filter(i =>
  i.json.estado === '⚠️ Pendiente'
).length;

const atrasados = datos.filter(i =>
  i.json.estado === '❌ Atrasado'
).length;


// ===============================
// HTML FINAL
// ===============================
const htmlCompleto = `
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
</head>

<body style="margin:0;padding:8px 10px;font-family:Arial,APTOS,sans-serif;font-size:12px;">

<h2 style="color:#7049BC;font-size:14px;margin:0;">
  <strong>Reporte de Horas – ${datos[0]?.json.mesCurso || ''}</strong>
</h2>

<p style="margin:8px 0;">
  Estimad@s, esperamos que este mensaje les encuentre bien:
</p>

<p style="margin:8px 0;">
  Como formalidad semanal, se comparte el reporte de ingreso de horas correspondiente
  al período entre las fechas: <strong>${repo.periodoTexto}</strong>.
</p>

<p style="margin:12px 0;">
  <span style="display:inline-block;background:#5CDB82;padding:10px;color:#000;">
    <strong>Nota:</strong> al momento de registrar las horas y su respectiva descripción,
    se solicita no utilizar signos especiales (como ", &, %, entre otros),
    ya que estos afectan la reportería.
  </span>
</p>

<table
  width="100%"
  cellpadding="0"
  cellspacing="0"
  border="1"
  bordercolor="#5838A3"
  style="
    width:100%;
    max-width:900px;
    border-collapse:collapse;
    font-size:12px;
    margin-top:15px;
    text-align:center;
  "
>

<thead>
<tr>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:3px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Área
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Colaborador
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Horas Esperadas
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Horas Ingresadas
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Diferencia
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Porcentaje
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Estado
  </th>

  <th bgcolor="#7049BC"
      style="border:1px solid #5838A3;
             color:#ffffff;
             padding:6px 0;
             padding-top: -10px;
             font-weight:bold;
             text-align:center;
             vertical-align:middle;
             line-height:normal;">
    Semanas Pendientes
  </th>

</tr>
</thead>

<tbody>
${datos.map(d => {

  const colorFila =
    d.json.estado === '✅ Al día' ? '#C9D6CC' :
    d.json.estado === '⚠️ Pendiente' ? '#E8DFC7' :
    '#F4CCCC';

  const colorBorde =
    d.json.estado === '✅ Al día' ? '#8BA88F' :
    d.json.estado === '⚠️ Pendiente' ? '#D4BC8E' :
    '#E89A9A';

  return `
  <tr>

    <td bgcolor="${colorFila}"
        style="margin-top:10px;margin-bottom:10px;padding:0;height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">${d.json.Area}
    </td>

    <td bgcolor="${colorFila}"
        style="margin-top:10px;margin-bottom:10px;padding:0;height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">
        <strong>${d.json.Nombre}</strong>
    </td>

    <td bgcolor="${colorFila}"
        style="margin-top:10px;margin-bottom:10px;padding:0;height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">
        <strong>${d.json.horasEsperadas}</strong>
    </td>

    <td bgcolor="${colorFila}"
        style="margin-top:10px;margin-bottom:10px;padding:0;height:height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">
        <strong>${d.json.horasIngresadas}</strong>
    </td>

    <td bgcolor="${colorFila}"
        style="margin-top:10px;margin-bottom:10px;padding:0;height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">${Math.abs(d.json.diferencia)}
    </td>

    <td bgcolor="${colorFila}"
        style="margin-top:10px;margin-bottom:10px;padding:0;height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">${d.json.porcentaje}%
    </td>

    <td bgcolor="${colorFila}"
        style="margin-top:10px;margin-bottom:10px;padding:0;height:height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">
        <strong>${d.json.estado}</strong>
    </td>

    <td bgcolor="${colorFila}"
        style="margin-top:10px;margin-bottom:10px;padding:0;height:18px;line-height:18px;vertical-align:middle;text-align:center;border:1px solid ${colorBorde};">${d.json.semanasPendientes}
    </td>

  </tr>
  `;
}).join('')}
</tbody>

</table>

<p style="color:#7049BC;font-weight:bold;margin-top:18px;font-size:14px;">
  Alcances del Reporte:
</p>

<ul style="margin:0;padding-left:18px;">
  <li><strong>Fecha inicio:</strong> ${periodoInicio}</li>
  <li><strong>Fecha fin:</strong> ${periodoFin}</li>
  <li><strong>Días hábiles considerados:</strong> ${diasLaborables}</li>
  <li><strong>Cantidad de horas contabilizadas en el mes:</strong> ${horasEsperadasPeriodo}</li>
  <li><strong>Total colaboradores:</strong> ${totalColaboradores}</li>
  <li><strong>Colaboradores al día:</strong> ${alDia}</li>
  <li><strong>Colaboradores pendientes:</strong> ${pendientes}</li>
  <li><strong>Colaboradores atrasados:</strong> ${atrasados}</li>
</ul>

<p style="margin-top:16px;">
  Frente a dudas, consultas o validación de métricas, comunicarse directamente
  con el <strong>área de control de gestión</strong>.
</p>

<p style="margin-top:14px;">
  Saludos cordiales.<br>
  Equipo de Infraestructura.
</p>

</body>
</html>
`;

return { htmlContent: htmlCompleto };

// ===============================
// NORMALIZAR TEXTO (quitar tildes)
// ===============================
function normalizar(texto) {
  return texto
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .trim();
}

// ===============================
// DATOS DEL REPOSITORIO
// ===============================
const repo = $('Repositorio').first().json;
const excepciones = repo.excepciones.map(e => normalizar(e));

// ===============================
// EXTRAER ARRAY REAL DE PERSONAS
// ===============================
const response = $input.first().json;
const personasAPI = response.person || [];

// ===============================
// FILTRAR SOLO ACTIVOS + NO EXCEPCIONES
// ===============================
const personasFinal = personasAPI
  .filter(p => p.active === "t")
  .filter(p => {
    const nombreCompleto = normalizar(
      `${p.firstname} ${p.lastname}`
    );
    return !excepciones.includes(nombreCompleto);
  });

// ===============================
// OUTPUT
// ===============================
return personasFinal.map(p => ({
  json: {
    personId: Number(p.id),
    nombre: `${p.firstname} ${p.lastname}`.trim(),
    fechaInicio: repo.fechaInicio,
    fechaFin: repo.fechaFin
  }
}));
